using System.Security.Cryptography; using System.Text; using Financeiro.Application.Interfaces.Security; namespace Financeiro.Infrastructure.Security; public class Sha256PasswordHasher : IPasswordHasher { public string Hash(string input){ using var sha=SHA256.Create(); return Convert.ToHexString(sha.ComputeHash(Encoding.UTF8.GetBytes(input))).ToLowerInvariant(); } public bool Verify(string input,string hash)=>Hash(input)==hash.ToLowerInvariant(); }
